AND A2.CODE_ID LIKE CONCAT('%', #{filterCodeId}, '%')
AND A2.CODE_ID_NM LIKE CONCAT('%', #{filterCodeIdNm}, '%')
AND B2.CL_CODE_NM LIKE CONCAT('%', #{filterClCodeNm}, '%')
AND A2.USE_AT = #{filterUseAt}
) A1 LIMIT #{lengthPage} OFFSET #{startIndex}

