UPDATE LETTCCMMNDETAILCODE
   SET CODE_NM               = COALESCE(#{codeNm}, '')
     , CODE_DC               = COALESCE(#{codeDc}, '')
     , ORDER_BY               = #{orderBy}
     , USE_AT                = COALESCE(#{useAt}, 'N')
     , LAST_UPDT_PNTTM       = SYSDATE()
     , LAST_UPDUSR_ID     	 = #{UNIQ_ID}
 WHERE CODE_ID               = #{codeId}
   AND CODE 				 = #{code}

